    "resultedInAction" BOOLEAN NOT NULL DEFAULT false,
    "timeToComplete" INTEGER,
    "userConfidence" INTEGER,
    "improvementSeen" BOOLEAN NOT NULL DEFAULT false,
    "followUpNeeded" BOOLEAN NOT NULL DEFAULT false,
    "deviceType" TEXT,
